{
  "name": "ID Design Mapper",
  "description": "An instructional design assistant that creates a draft course design map by aligning module objectives and course items to high-level course learning objectives.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CourseItem {
  type: 'Reading' | 'Multimedia' | 'Quiz' | 'Assignment' | 'Discussion' | 'Other';
  title: string;
}

export interface ModuleObjective {
  objective: string;
  items: CourseItem[];
}

export interface CLOMapping {
  clo: string;
  alignedModules: ModuleObjective[];
  findings: string;
  recommendations: string;
}

export interface DesignMap {
  courseTitle: string;
  mappings: CLOMapping[];
  overallSummary: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DesignMap } from "../types";

export const generateDesignMap = async (
  clos: string,
  documentContent: string,
  courseContext: string
): Promise<DesignMap> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `
    You are an expert instructional designer and evaluation specialist.
    Your task is to create a draft course design map.

    PROCESS:
    1. Analyze the provided Design Document for an ${courseContext} course.
    2. Extract Module Objectives (found under "Module Introduction" sections).
    3. Identify and list related course items (Readings, Multimedia, Quizzes, Assignments, Discussions) for each objective.
    4. Map these Module Objectives and items to the Course Learning Objectives (CLOs) provided by the user.
    5. Exclude content from "Instructor Resources", "Student Resources", and "Getting Started" modules.
    6. For each CLO, provide a "Findings" summary and "Recommendations" for improvement.

    OUTPUT FORMAT:
    Return a structured JSON object.
  `;

  const prompt = `
    COURSE LEARNING OBJECTIVES (CLOs):
    ${clos}

    DESIGN DOCUMENT CONTENT:
    ${documentContent}

    COURSE CONTEXT:
    ${courseContext}
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          courseTitle: { type: Type.STRING },
          mappings: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                clo: { type: Type.STRING, description: "The specific Course Learning Objective text." },
                alignedModules: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      objective: { type: Type.STRING, description: "The module objective text." },
                      items: {
                        type: Type.ARRAY,
                        items: {
                          type: Type.OBJECT,
                          properties: {
                            type: { type: Type.STRING, enum: ['Reading', 'Multimedia', 'Quiz', 'Assignment', 'Discussion', 'Other'] },
                            title: { type: Type.STRING }
                          },
                          required: ["type", "title"]
                        }
                      }
                    },
                    required: ["objective", "items"]
                  }
                },
                findings: { type: Type.STRING, description: "Critique of how well this CLO is addressed." },
                recommendations: { type: Type.STRING, description: "Specific advice for improving alignment or depth." }
              },
              required: ["clo", "alignedModules", "findings", "recommendations"]
            }
          },
          overallSummary: { type: Type.STRING }
        },
        required: ["courseTitle", "mappings", "overallSummary"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No response generated from the model.");
  }

  return JSON.parse(response.text) as DesignMap;
};

