import React from 'react';
import { DesignMap, CLOMapping, ModuleObjective } from '../types';

interface Props {
  data: DesignMap;
  onReset: () => void;
}

const ItemIcon = ({ type }: { type: string }) => {
  switch (type) {
    case 'Reading': return '📄';
    case 'Multimedia': return '🎬';
    case 'Quiz': return '📝';
    case 'Assignment': return '📤';
    case 'Discussion': return '💬';
    default: return '🔗';
  }
};

