                <div className="grid gap-4">
                  {mapping.alignedModules.length > 0 ? (
                    mapping.alignedModules.map((mo, moIdx) => (
                      <div key={moIdx} className="border border-slate-100 rounded-xl p-5 bg-slate-50/50">
