import React, { useState, useCallback } from 'react';
import { generateDesignMap } from './services/geminiService';
import { DesignMap } from './types';
import { LoadingOverlay } from './components/LoadingOverlay';
import { MappingResult } from './components/MappingResult';

const App: React.FC = () => {
  const [clos, setClos] = useState('');
  const [documentContent, setDocumentContent] = useState('');
  const [courseContext, setCourseContext] = useState('Undergraduate Math');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DesignMap | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!clos.trim() || !documentContent.trim()) {
      setError('Please provide both Course Learning Objectives and the Design Document content.');
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      const data = await generateDesignMap(clos, documentContent, courseContext);
      setResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to generate design map. Please check your API key and input.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setDocumentContent(event.target?.result as string);
      };
      reader.readAsText(file);
    }
  };

  if (result) {
    return (
      <div className="max-w-6xl mx-auto px-4 py-12">
        <MappingResult data={result} onReset={() => setResult(null)} />
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20">
      {isLoading && <LoadingOverlay />}

      {/* Hero Section */}
      <header className="bg-slate-900 text-white pt-20 pb-24 px-4 text-center">
        <div className="max-w-4xl mx-auto">
