              </div>
              <textarea
                value={documentContent}
                onChange={(e) => setDocumentContent(e.target.value)}
                placeholder="Paste the full content of your module design document here. Ensure it includes Module Introduction headers with objectives and lists of items like readings, quizzes, etc."
