                  </label>
                  <textarea
                    value={clos}
                    onChange={(e) => setClos(e.target.value)}
                    placeholder="Paste your course-level learning objectives here..."
                    className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white resize-none font-mono text-sm leading-relaxed"
                  />
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">
                    3. Program Learning Objectives (PLOs)
                  </label>
                  <textarea
                    value={plos}
                    onChange={(e) => setPlos(e.target.value)}
                    placeholder="Optional: Paste Program Learning Objectives..."
                    className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white resize-none text-sm"
