import { DesignMap } from './types';
import { LoadingOverlay } from './components/LoadingOverlay';
import { MappingResult } from './components/MappingResult';

// External global variable types for Mammoth and PDF.js
declare const mammoth: any;
declare const pdfjsLib: any;

const App: React.FC = () => {
  const [clos, setClos] = useState('');
  const [plos, setPlos] = useState('');
  const [ulos, setUlos] = useState('');
  const [objectiveLocation, setObjectiveLocation] = useState('This design document contains module objectives under section headers titled Module Introduction. OR This design document does not contain module objectives');
  const [exclusions, setExclusions] = useState('Instructor Resources, Student Resources, and Getting Started modules. Also exclude any unpublished course content.');
  const [documentContent, setDocumentContent] = useState('');
  const [contextType, setContextType] = useState('Undergraduate');
  const [customContext, setCustomContext] = useState('');
  const [courseInfo, setCourseInfo] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DesignMap | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isParsing, setIsParsing] = useState(false);

  const handleGenerate = async () => {
    if (!clos.trim() || !documentContent.trim()) {
      setError('Please provide both Course Learning Objectives and the Design Document content.');
      return;
    }

    const finalContext = contextType === 'Other' ? customContext : contextType;
    if (contextType === 'Other' && !customContext.trim()) {
      setError('Please specify the custom course context.');
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      const data = await generateDesignMap(
        clos, 
        documentContent, 
        finalContext,
        plos,
        ulos,
        exclusions,
        objectiveLocation,
        courseInfo
      );
      setResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to generate design map. Please check your API key and input.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsParsing(true);
    setError(null);

    try {
      if (file.type === 'application/pdf') {
        const arrayBuffer = await file.arrayBuffer();
        pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.4.120/pdf.worker.min.js';
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        let fullText = '';
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const textContent = await page.getTextContent();
          const pageText = textContent.items.map((item: any) => item.str).join(' ');
          fullText += pageText + '\n';
        }
        setDocumentContent(fullText);
      } else if (file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        setDocumentContent(result.value);
      } else {
        // Assume text-based for other types (txt, md, etc)
        const text = await file.text();
        setDocumentContent(text);
      }
    } catch (err) {
      console.error('File parsing error:', err);
      setError('Failed to extract text from the file. Please try pasting the content directly.');
    } finally {
      setIsParsing(false);
    }
  };

  if (result) {
    return (
      <div className="max-w-6xl mx-auto px-4 py-12">
        <MappingResult data={result} onReset={() => setResult(null)} />
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20">
      {isLoading && <LoadingOverlay />}

      {/* Hero Section */}
      <header className="bg-slate-900 text-white pt-20 pb-24 px-4 text-center">
        <div className="max-w-4xl mx-auto">
          <h1 className="text-4xl md:text-5xl font-extrabold mb-6 tracking-tight leading-tight">
            Curriculum Alignment <span className="text-blue-400">Simplified.</span>
          </h1>
          <p className="text-xl text-slate-400 max-w-2xl mx-auto leading-relaxed">
            Upload your course design document and objectives. Our AI-powered assistant will map your modules and evaluate curriculum alignment.
          </p>
        </div>
      </header>

      {/* Input Section */}
      <main className="max-w-7xl mx-auto px-4 -mt-12">
        <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-200">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

            {/* Left Column: Objectives & Config */}
            <div className="lg:col-span-5 space-y-6">
              <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100 space-y-6">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">
                    1. Course Context
                  </label>
                  <select
                    value={contextType}
                    onChange={(e) => setContextType(e.target.value)}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white mb-3"
                  >
                    <option value="Undergraduate">Undergraduate</option>
                    <option value="Master's">Master's</option>
                    <option value="Doctoral">Doctoral</option>
                    <option value="Professional Development">Professional Development</option>
                    <option value="Other">Other</option>
                  </select>
                  {contextType === 'Other' && (
                    <input
                      type="text"
                      value={customContext}
                      onChange={(e) => setCustomContext(e.target.value)}
                      placeholder="Please specify context..."
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white animate-in slide-in-from-top-2"
                    />
                  )}
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">
                    2. Course Dept, ###, & Title
                  </label>
                  <input
                    type="text"
                    value={courseInfo}
                    onChange={(e) => setCourseInfo(e.target.value)}
                    placeholder="MATH 108: Intermediate Algebra"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white"
                  />
