import React, { useState } from 'react';
import { generateDesignMap } from './services/geminiService';
import { DesignMap } from './types';
import { LoadingOverlay } from './components/LoadingOverlay';
import { MappingResult } from './components/MappingResult';

// External global variable types for Mammoth and PDF.js
declare const mammoth: any;
declare const pdfjsLib: any;

const App: React.FC = () => {
  const [clos, setClos] = useState('');
  const [plos, setPlos] = useState('');
  const [ulos, setUlos] = useState('');
  const [objectiveLocation, setObjectiveLocation] = useState('This design document contains module objectives under section headers titled Module Introduction. OR This design document does not contain module objectives');
  const [exclusions, setExclusions] = useState('Instructor Resources, Student Resources, and Getting Started modules. Also exclude any unpublished course content.');
  const [documentContent, setDocumentContent] = useState('');
  const [contextType, setContextType] = useState('Undergraduate');
  const [customContext, setCustomContext] = useState('');
  const [courseInfo, setCourseInfo] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DesignMap | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isParsing, setIsParsing] = useState(false);
  const [isAccordionOpen, setIsAccordionOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);

  const handleGenerate = async () => {
    if (!clos.trim() || !documentContent.trim()) {
      setError('Please provide both Course Learning Objectives and the Design Document content.');
      return;
    }

    const finalContext = contextType === 'Other' ? customContext : contextType;
    if (contextType === 'Other' && !customContext.trim()) {
      setError('Please specify the custom course context.');
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      const data = await generateDesignMap(
        clos, 
        documentContent, 
        finalContext,
        plos,
        ulos,
        exclusions,
        objectiveLocation,
        courseInfo
      );
      setResult(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to generate design map. Please check your API key and input.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsParsing(true);
    setError(null);

    try {
      if (file.type === 'application/pdf') {
        const arrayBuffer = await file.arrayBuffer();
        pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.4.120/pdf.worker.min.js';
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        let fullText = '';
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const textContent = await page.getTextContent();
          const pageText = textContent.items.map((item: any) => item.str).join(' ');
          fullText += pageText + '\n';
        }
        setDocumentContent(fullText);
      } else if (file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        setDocumentContent(result.value);
      } else {
        // Assume text-based for other types (txt, md, etc)
        const text = await file.text();
        setDocumentContent(text);
      }
    } catch (err) {
      console.error('File parsing error:', err);
      setError('Failed to extract text from the file. Please try pasting the content directly.');
    } finally {
      setIsParsing(false);
    }
  };

  if (result) {
    return (
      <div className="max-w-6xl mx-auto px-4 py-12">
        <MappingResult data={result} onReset={() => setResult(null)} />
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20">
      {isLoading && <LoadingOverlay />}

      {/* Hero Section - Compacted Banner */}
      <header className="bg-[#0033A0] text-white pt-10 pb-6 px-4 relative shadow-md">
        <div className="max-w-7xl mx-auto flex flex-col justify-between">
          <div className="text-center mb-6">
            <h1 className="text-3xl md:text-5xl font-extrabold tracking-tight leading-tight">
              eCampus Course Alignment Assistant
            </h1>
          </div>

          {/* Help Center at Bottom Left of Banner - More compact */}
          <div className="self-start w-full md:w-72">
            <div className="bg-white/10 backdrop-blur-md rounded-xl border border-white/20 overflow-hidden transition-all duration-300">
              <button 
                onClick={() => setIsHelpOpen(!isHelpOpen)}
                className="w-full flex items-center justify-between p-2.5 hover:bg-white/10 transition-colors text-left outline-none"
              >
                <span className="font-bold text-white flex items-center gap-2 text-xs uppercase tracking-wide">
                  <svg className="w-4 h-4 shrink-0 text-blue-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                  Help Center
                </span>
                <svg 
                  className={`w-4 h-4 text-blue-200 transition-transform duration-300 ${isHelpOpen ? 'rotate-180' : ''}`} 
                  fill="none" stroke="currentColor" viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path>
                </svg>
              </button>
              {isHelpOpen && (
                <div className="p-1.5 bg-white/5 border-t border-white/10 animate-in slide-in-from-top-2 duration-200">
                  <div className="flex flex-col gap-0.5">
                    <a 
                      href="https://docs.google.com/document/d/1g4WLYmFsdiXvBi0LPZPCMgv6SwnhTBxzh7dLmMt0O40/edit?tab=t.0" 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center gap-2 p-2 rounded-lg hover:bg-white/10 text-blue-50 text-xs font-medium transition-colors"
                    >
                      <svg className="w-3.5 h-3.5 text-blue-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                      How to use this app
                    </a>
                    <a 
                      href="https://boisestateecampus.atlassian.net/wiki/spaces/EKB/pages/3503652868/The+eCampus+Content+Export+Tool+Canvas+to+Google+Doc" 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center gap-2 p-2 rounded-lg hover:bg-white/10 text-blue-50 text-xs font-medium transition-colors"
                    >
                      <svg className="w-3.5 h-3.5 text-blue-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                      Companion App: Export Tool
                    </a>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-7xl mx-auto px-4 mt-8">

        {/* Verification Accordion at Top of Form */}
        <section className="mb-8">
          <div className="bg-white rounded-2xl border border-blue-200 shadow-md overflow-hidden transition-all duration-300">
            <button 
              onClick={() => setIsAccordionOpen(!isAccordionOpen)}
