              onClick={() => setIsAccordionOpen(!isAccordionOpen)}
              className="w-full flex items-center justify-between p-5 bg-white hover:bg-slate-50 transition-colors text-left outline-none group"
            >
              <span className="font-bold text-[#0033A0] flex items-center gap-3">
                <svg className="w-5 h-5 shrink-0 text-[#0033A0]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                Alignment Needs To Be Verified
              </span>
              <svg 
                className={`w-5 h-5 text-[#0033A0] transition-transform duration-300 ${isAccordionOpen ? 'rotate-180' : ''}`} 
                fill="none" stroke="currentColor" viewBox="0 0 24 24"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path>
              </svg>
            </button>
            {isAccordionOpen && (
              <div className="p-6 text-[#0033A0] text-sm md:text-base leading-relaxed bg-white border-t border-blue-100 animate-in slide-in-from-top-4 duration-300">
                <p className="mb-4">
                  Course design maps are usually the result of collaboration between an instructional design consultant and a faculty developer. This process is not meant to replace that; instead it should serve as a first draft or a next-best option.
                </p>
                <p className="mb-4">
                  After getting the draft design map, carefully check it yourself against the course content, use your best judgement to make edits, and then verify the alignment with the Faculty Developer (FD), Instructor of Record (IoR), or whomever has the qualifications or authority to approve the accuracy of the draft map.
                </p>
                <p className="font-bold">
                  Treat the AI-generated map as a draft, not a final product.
                </p>
              </div>
            )}
          </div>
        </section>

        {/* Input Form Card */}
        <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-200">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

            {/* Left Column: Objectives & Config */}
