                  >
                    <option value="Undergraduate">Undergraduate</option>
                    <option value="Master's">Master's</option>
                    <option value="Doctoral">Doctoral</option>
                    <option value="Professional Development">Professional Development</option>
                    <option value="Other">Other</option>
                  </select>
                  {contextType === 'Other' && (
                    <input
                      type="text"
                      value={customContext}
                      onChange={(e) => setCustomContext(e.target.value)}
                      placeholder="Please specify context..."
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white animate-in slide-in-from-top-2"
                    />
