              <button 
                onClick={() => setIsHelpOpen(!isHelpOpen)}
                className="w-full flex items-center justify-between p-5 bg-white hover:bg-slate-50 transition-colors text-left outline-none"
              >
                <span className="font-bold text-[#0033A0] flex items-center gap-3">
                  <svg className="w-5 h-5 shrink-0 text-[#0033A0]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                  Help Center
                </span>
                <svg 
                  className={`w-5 h-5 text-[#0033A0] transition-transform duration-300 ${isHelpOpen ? 'rotate-180' : ''}`} 
                  fill="none" stroke="currentColor" viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path>
                </svg>
              </button>
              {isHelpOpen && (
                <div className="p-4 bg-white border-t border-slate-100 animate-in slide-in-from-top-4 duration-300">
