import React from 'react';
import { DesignMap, CLOMapping, ModuleObjective } from '../types';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ListLevel, LevelFormat, BorderStyle } from 'docx';

interface Props {
  data: DesignMap;
  onReset: () => void;
}

const ItemIcon = ({ type }: { type: string }) => {
  switch (type) {
    case 'Reading': return '📄';
    case 'Multimedia': return '🎬';
    case 'Quiz': return '📝';
    case 'Assignment': return '📤';
    case 'Discussion': return '💬';
    default: return '🔗';
  }
};

export const MappingResult: React.FC<Props> = ({ data, onReset }) => {
  const downloadWord = async () => {
    const sections = [];

    // Title Section
    sections.push({
      properties: {},
      children: [
        new Paragraph({
          text: data.courseTitle,
          heading: HeadingLevel.TITLE,
          alignment: AlignmentType.CENTER,
          spacing: { after: 200 },
        }),
        new Paragraph({
          text: "Course Design Alignment Map",
          alignment: AlignmentType.CENTER,
          spacing: { after: 400 },
        }),
        new Paragraph({
          children: [
            new TextRun({ text: "Executive Summary", bold: true, size: 28 }),
          ],
          spacing: { after: 200 },
        }),
        new Paragraph({
          text: data.overallSummary,
          spacing: { after: 400 },
        }),
      ],
    });

    // CLO Mappings
    data.mappings.forEach((mapping, idx) => {
      const mappingChildren = [
        new Paragraph({
          children: [
            new TextRun({ text: `Course Learning Objective ${idx + 1}`, bold: true, size: 24, color: "0033A0" }),
          ],
          spacing: { before: 400, after: 200 },
          border: {
            top: { color: "CCCCCC", space: 1, style: BorderStyle.SINGLE, size: 6 },
          },
        }),
        new Paragraph({
          children: [
            new TextRun({ text: mapping.clo, bold: true, size: 28 }),
          ],
          spacing: { after: 300 },
        }),
      ];

      mapping.alignedModules.forEach((mo, moIdx) => {
        mappingChildren.push(
          new Paragraph({
            children: [
              new TextRun({ text: `Module Objective ${moIdx + 1}: `, bold: true }),
              new TextRun({ text: mo.objective }),
            ],
            spacing: { before: 200, after: 100 },
            bullet: { level: 0 },
          })
        );

        mo.items.forEach((item) => {
          mappingChildren.push(
            new Paragraph({
              children: [
                new TextRun({ text: `[${item.type}] ${item.title}` }),
              ],
              spacing: { after: 50 },
              bullet: { level: 1 },
            })
          );
        });
      });

      if (mapping.alignedModules.length === 0) {
        mappingChildren.push(new Paragraph({ text: "No specific module objectives aligned to this CLO.", italics: true }));
      }

      mappingChildren.push(
        new Paragraph({
          children: [new TextRun({ text: "Findings", bold: true, size: 24 })],
          spacing: { before: 300, after: 100 },
        }),
        new Paragraph({
          text: mapping.findings,
          spacing: { after: 200 },
        }),
        new Paragraph({
          children: [new TextRun({ text: "Recommendations", bold: true, size: 24 })],
          spacing: { before: 100, after: 100 },
        }),
        new Paragraph({
          text: mapping.recommendations,
          spacing: { after: 400 },
        })
      );

      sections[0].children.push(...mappingChildren);
    });

    const doc = new Document({
      sections: sections,
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${data.courseTitle.replace(/[^a-z0-9]/gi, '_')}_Alignment_Report.docx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-10 rounded-xl shadow-sm border border-slate-200 gap-6">
