            Reset and Start Over
          </button>
        </div>
      </div>

      <div className="bg-blue-50 border-l-4 border-blue-500 p-10 rounded-r-xl">
        <h3 className="text-lg font-bold text-blue-800 uppercase tracking-wider mb-4">Executive Summary</h3>
        <p className="text-slate-700 text-2xl leading-relaxed">{data.overallSummary}</p>
      </div>

      <div className="space-y-16">
        {data.mappings.map((mapping, idx) => (
          <section key={idx} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="bg-slate-800 p-10 text-white">
              <span className="text-base font-bold uppercase text-slate-400 tracking-widest block mb-4">Course Learning Objective {idx + 1}</span>
              <h3 className="text-3xl font-semibold leading-snug">{mapping.clo}</h3>
