                  {mapping.alignedModules.length > 0 ? (
                    mapping.alignedModules.map((mo, moIdx) => (
                      <div key={moIdx} className="border border-slate-100 rounded-xl p-8 bg-slate-50/50">
                        <div className="flex items-start gap-6">
                          <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 text-lg font-bold shrink-0 mt-0.5">
                            {moIdx + 1}
                          </div>
                          <div className="flex-1">
