                  <input
                    type="text"
                    value={courseInfo}
                    onChange={(e) => setCourseInfo(e.target.value)}
                    placeholder="e.g. MATH 108: Intermediate Algebra"
                    className="w-full px-5 py-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white text-lg"
                  />
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">
                    3. Course Learning Objectives (CLOs) <span className="text-red-500">*</span>
                  </label>
                  <textarea
                    value={clos}
                    onChange={(e) => setClos(e.target.value)}
                    placeholder="Paste your course-level learning objectives here..."
