        new Paragraph({ text: mapping.recommendations, spacing: { after: 300 } })
      );
    });

    // 3. Section: Alignment Organized By Modules
    docChildren.push(
      new Paragraph({
        children: [new TextRun({ text: "Alignment Organized By Modules", bold: true, size: 32, color: "E36C09" })],
        alignment: AlignmentType.CENTER,
        spacing: { before: 800, after: 400 },
        pageBreakBefore: true,
      })
    );

    Array.from(modulesMap.values()).forEach((mod, idx) => {
      docChildren.push(
        new Paragraph({
          children: [new TextRun({ text: `Module ${idx + 1}`, bold: true, size: 28, color: "0033A0" })],
          spacing: { before: 300, after: 100 },
        }),
        new Paragraph({
          children: [new TextRun({ text: "Relevant CLOs, MLO, & Associated Assessments/Activities", bold: true })],
          spacing: { before: 100, after: 100 },
        }),
        new Paragraph({
          text: mod.objective,
          spacing: { after: 100 }
        })
      );

      // List associated CLOs
      docChildren.push(new Paragraph({ children: [new TextRun({ text: "Associated CLOs:", bold: true, size: 20 })], spacing: { before: 50 } }));
      mod.clos.forEach(cloText => {
        docChildren.push(new Paragraph({ text: cloText, bullet: { level: 0 }, spacing: { after: 50 } }));
      });

      // List Items
      docChildren.push(new Paragraph({ children: [new TextRun({ text: "Associated Items:", bold: true, size: 20 })], spacing: { before: 50 } }));
      mod.items.forEach(item => {
        docChildren.push(
          new Paragraph({
            text: `[${item.type}] ${item.title}`,
            bullet: { level: 0 },
            spacing: { after: 50 }
          })
        );
      });

      docChildren.push(
        new Paragraph({ children: [new TextRun({ text: "Findings", bold: true })], spacing: { before: 200 } }),
        new Paragraph({ text: mod.findings.join(" "), spacing: { after: 100 } }),
        new Paragraph({ children: [new TextRun({ text: "Recommendations", bold: true })], spacing: { before: 100 } }),
        new Paragraph({ text: mod.recommendations.join(" "), spacing: { after: 300 } })
      );
    });

    const doc = new Document({
      sections: [{
        properties: {},
        children: docChildren,
      }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${data.courseTitle.replace(/[^a-z0-9]/gi, '_')}_Alignment_Report.docx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

