                    onChange={(e) => setCourseInfo(e.target.value)}
                    placeholder="e.g. MATH 108: Intermediate Algebra"
                    className="w-full px-5 py-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white text-lg"
                  />
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-500 tracking-wider mb-3">
