                    >
                      <svg className="w-6 h-6 text-blue-500 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                      Companion App: The eCampus Content Export Tool
                    </a>

                    {/* Nested Possible Use Cases Accordion */}
                    <div className="mt-2 border border-slate-200 rounded-xl overflow-hidden bg-slate-50">
                      <button 
                        onClick={() => setIsUseCasesOpen(!isUseCasesOpen)}
                        className="w-full flex items-center justify-between p-4 hover:bg-slate-100 transition-colors text-left outline-none group"
                      >
                        <span className="font-bold text-slate-700 text-base flex items-center gap-2">
                          <svg className="w-5 h-5 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"></path></svg>
                          Possible Use Cases
                        </span>
                        <svg 
                          className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${isUseCasesOpen ? 'rotate-180' : ''}`} 
                          fill="none" stroke="currentColor" viewBox="0 0 24 24"
                        >
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path>
                        </svg>
                      </button>
                      {isUseCasesOpen && (
                        <div className="p-5 bg-white border-t border-slate-200 animate-in slide-in-from-top-2 duration-300">
                          <ul className="list-disc ml-5 space-y-3 text-slate-600 text-base leading-relaxed">
                            <li>A course redesign project in which course content has significantly changed over time but the alignment table/course map has not been updated;</li>
