                </div>
              )}
            </div>
          </section>
        </div>

        {/* Input Form Card */}
        <div className="bg-white rounded-2xl shadow-xl p-10 border border-slate-200">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

