export const MappingResult: React.FC<Props> = ({ data, onReset }) => {
  const downloadWord = async () => {
    // Grouping by modules for the second section
    const modulesMap = new Map<string, { 
      objective: string; 
      clos: string[]; 
      items: CourseItem[];
      findings: string[];
      recommendations: string[];
    }>();

    data.mappings.forEach(m => {
      m.alignedModules.forEach(am => {
        if (!modulesMap.has(am.objective)) {
          modulesMap.set(am.objective, {
            objective: am.objective,
            clos: [m.clo],
            items: [...am.items],
            findings: [m.findings],
            recommendations: [m.recommendations]
          });
        } else {
          const existing = modulesMap.get(am.objective)!;
          if (!existing.clos.includes(m.clo)) existing.clos.push(m.clo);
          am.items.forEach(item => {
            if (!existing.items.find(ei => ei.title === item.title && ei.type === item.type)) {
              existing.items.push(item);
            }
          });
          if (!existing.findings.includes(m.findings)) existing.findings.push(m.findings);
          if (!existing.recommendations.includes(m.recommendations)) existing.recommendations.push(m.recommendations);
        }
      });
