export interface CLOMapping {
  clo: string;
  alignedModules: ModuleObjective[];
  findings: string;
  recommendations: string;
}

export interface QMFeedback {
  qm2_1: string;
  qm2_2: string;
  qm2_3: string;
  qm2_4: string;
  qm2_5: string;
}

export interface DesignMap {
  courseTitle: string;
  courseLength: string;
  overallSummary: string;
  qmFeedback: QMFeedback;
  mappings: CLOMapping[];
}

export interface AutoFillResults {
  courseContext: string;
  courseInfo: string;
  courseLength: string;
  clos: string;
  plos: string;
  ulos: string;
  objectiveLocation: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DesignMap, AutoFillResults } from "../types";

export const analyzeCourseDocument = async (content: string): Promise<AutoFillResults> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `
    You are an expert instructional designer. Analyze the provided course design document and extract specific details to help fill out a course alignment form.

    EXTRACT:
    - Course Context: Undergraduate, Master's, Doctoral, or Professional Development.
    - Course Info: Dept, number, and title (e.g., MATH 108: Intermediate Algebra).
    - Course Length: Duration of the course (e.g., 7 weeks, 15 weeks, 1 semester).
    - CLOs: Course Learning Objectives.
    - PLOs: Program Learning Objectives (if present).
    - ULOs: University Learning Objectives (if present).
    - Objective Location: Where module-level objectives are typically found in this specific document.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze this document content and return JSON:\n\n${content.substring(0, 20000)}`, // Truncate if extreme, but flash handles large context
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          courseContext: { type: Type.STRING, enum: ['Undergraduate', "Master's", 'Doctoral', 'Professional Development', 'Other'] },
          courseInfo: { type: Type.STRING },
          courseLength: { type: Type.STRING },
          clos: { type: Type.STRING },
          plos: { type: Type.STRING },
          ulos: { type: Type.STRING },
          objectiveLocation: { type: Type.STRING }
        },
        required: ["courseContext", "courseInfo", "courseLength", "clos", "objectiveLocation"]
      }
    }
  });

  if (!response.text) throw new Error("Analysis failed");
  return JSON.parse(response.text) as AutoFillResults;
};

export const generateDesignMap = async (
  clos: string,
  documentContent: string,
  courseContext: string,
  courseLength: string,
  plos?: string,
  ulos?: string,
  exclusions?: string,
  objectiveLocation?: string,
  courseInfo?: string,
  additionalInfo?: string
): Promise<DesignMap> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `
    You are an expert instructional designer and evaluation specialist for Boise State University.
    Your task is to create a draft course design map and evaluate it against Boise State's QM+ Standards.

    COURSE PARAMETERS:
    - Level: ${courseContext}
    - Duration: ${courseLength}

    GUIDANCE ON QM+ STANDARDS (General Standard 2):
    - QM 2.1: Course-level objectives (CLOs) must be measurable (e.g., use active verbs, avoid "understand" or "learn").
    - QM 2.2: Module-level objectives (MLOs) must be measurable and consistent with CLOs.
    - QM 2.3: Objectives must be clearly stated, learner-centered (written from learner's perspective), and prominently located.
    - QM 2.4: The relationship between objectives, learning activities, and assessments must be clear (a "straight line").
    - QM 2.5: Objectives must reflect the course level (e.g., 100-level = identify/describe; 400-level = evaluate/analyze; 800-level = design/create).

    PROCESS:
    1. Analyze the provided Design Document for an ${courseContext} course that lasts ${courseLength}.
    2. Extract Module Objectives. Guidance on location: ${objectiveLocation || "Found under 'Module Introduction' sections"}.
    3. Identify and list related course items (Readings, Multimedia, Quizzes, Assignments, Discussions) for each objective.
    4. Map these MLOs and items to the Course Learning Objectives (CLOs) provided.
    5. Evaluate the course content against QM 2.1 through 2.5 based on the guidance above.
    6. STRICTLY EXCLUDE content from modules or sections matching: ${exclusions || "Instructor Resources, Student Resources, and Getting Started modules. Also exclude any unpublished course content."}.
    7. For each CLO, provide "Findings" and "Recommendations".

    OUTPUT FORMAT:
    Return a JSON object matching the requested schema. Use the Course identification: ${courseInfo || "DEPT ###: Course Title"}.
  `;

  const prompt = `
    COURSE INFO: ${courseInfo || 'N/A'}
    COURSE LENGTH: ${courseLength}
    CLOs: ${clos}
    ${plos ? `PLOs: ${plos}` : ''}
    ${ulos ? `ULOs: ${ulos}` : ''}
    DESIGN DOC: ${documentContent}
    CONTEXT: ${courseContext}
    ${additionalInfo ? `ADDITIONAL INFO: ${additionalInfo}` : ''}
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          courseTitle: { type: Type.STRING },
          courseLength: { type: Type.STRING },
          overallSummary: { type: Type.STRING, description: "Executive Summary of the alignment state." },
          qmFeedback: {
            type: Type.OBJECT,
            properties: {
              qm2_1: { type: Type.STRING, description: "Feedback for QM 2.1 (Measurable CLOs)" },
              qm2_2: { type: Type.STRING, description: "Feedback for QM 2.2 (Measurable/Consistent MLOs)" },
              qm2_3: { type: Type.STRING, description: "Feedback for QM 2.3 (Clearly stated/Learner-centered)" },
              qm2_4: { type: Type.STRING, description: "Feedback for QM 2.4 (Clear relationship/Straight line)" },
              qm2_5: { type: Type.STRING, description: "Feedback for QM 2.5 (Level appropriateness)" }
            },
            required: ["qm2_1", "qm2_2", "qm2_3", "qm2_4", "qm2_5"]
          },
          mappings: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                clo: { type: Type.STRING },
                alignedModules: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      objective: { type: Type.STRING },
                      items: {
                        type: Type.ARRAY,
                        items: {
                          type: Type.OBJECT,
                          properties: {
                            type: { type: Type.STRING, enum: ['Reading', 'Multimedia', 'Quiz', 'Assignment', 'Discussion', 'Other'] },
                            title: { type: Type.STRING }
                          },
                          required: ["type", "title"]
                        }
                      }
                    },
                    required: ["objective", "items"]
                  }
                },
                findings: { type: Type.STRING },
                recommendations: { type: Type.STRING }
              },
              required: ["clo", "alignedModules", "findings", "recommendations"]
            }
          }
        },
        required: ["courseTitle", "courseLength", "overallSummary", "qmFeedback", "mappings"]
      }
    }
  });

  if (!response.text) throw new Error("No response generated.");
  return JSON.parse(response.text) as DesignMap;
};

import React from 'react';
import { DesignMap, CLOMapping, ModuleObjective, CourseItem } from '../types';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } from 'docx';

interface Props {
  data: DesignMap;
  onReset: () => void;
}

const ItemIcon = ({ type }: { type: string }) => {
  switch (type) {
    case 'Reading': return '📄';
    case 'Multimedia': return '🎬';
    case 'Quiz': return '📝';
    case 'Assignment': return '📤';
    case 'Discussion': return '💬';
    default: return '🔗';
  }
};

export const MappingResult: React.FC<Props> = ({ data, onReset }) => {
  const downloadWord = async () => {
    // Grouping by modules for the second section
    const modulesMap = new Map<string, { 
      objective: string; 
      clos: string[]; 
      items: CourseItem[];
      findings: string[];
      recommendations: string[];
    }>();

    data.mappings.forEach(m => {
      m.alignedModules.forEach(am => {
        if (!modulesMap.has(am.objective)) {
          modulesMap.set(am.objective, {
            objective: am.objective,
            clos: [m.clo],
            items: [...am.items],
            findings: [m.findings],
            recommendations: [m.recommendations]
          });
        } else {
          const existing = modulesMap.get(am.objective)!;
          if (!existing.clos.includes(m.clo)) existing.clos.push(m.clo);
          am.items.forEach(item => {
            if (!existing.items.find(ei => ei.title === item.title && ei.type === item.type)) {
              existing.items.push(item);
            }
          });
          if (!existing.findings.includes(m.findings)) existing.findings.push(m.findings);
          if (!existing.recommendations.includes(m.recommendations)) existing.recommendations.push(m.recommendations);
        }
      });
    });

    const docChildren: any[] = [];

    // Header
    docChildren.push(
      new Paragraph({
        children: [new TextRun({ text: data.courseTitle, bold: true, size: 48 })],
        alignment: AlignmentType.CENTER,
        spacing: { before: 400, after: 100 },
      }),
      new Paragraph({
        children: [new TextRun({ text: "Course Design Alignment Report", size: 28, color: "666666" })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 400 },
      }),
      new Paragraph({
        children: [new TextRun({ text: `Course Length: ${data.courseLength}`, size: 24, color: "333333" })],
        alignment: AlignmentType.CENTER,
        spacing: { after: 200 },
      }),
      new Paragraph({
        children: [new TextRun({ text: "Executive Summary", bold: true, size: 32, color: "E36C09" })],
        alignment: AlignmentType.CENTER,
        spacing: { before: 400, after: 200 },
      }),
      new Paragraph({
        text: data.overallSummary,
        spacing: { after: 600 },
      })
    );

    // QM Feedback Section
    docChildren.push(
      new Paragraph({
        children: [new TextRun({ text: "Feedback On Objectives (QM General Standard 2)", bold: true, size: 32, color: "E36C09" })],
        alignment: AlignmentType.CENTER,
        spacing: { before: 400, after: 400 },
      }),
      new Paragraph({ children: [new TextRun({ text: "QM 2.1: The course-level learning objectives describe outcomes that are measurable.", bold: true, color: "0033A0" })] }),
      new Paragraph({ text: data.qmFeedback.qm2_1, spacing: { after: 200 } }),
      new Paragraph({ children: [new TextRun({ text: "QM 2.2: The module/unit-level learning objectives describe outcomes that are measurable and consistent with the course-level objectives.", bold: true, color: "0033A0" })] }),
      new Paragraph({ text: data.qmFeedback.qm2_2, spacing: { after: 200 } }),
      new Paragraph({ children: [new TextRun({ text: "QM 2.3: Learning objectives are clearly stated, are learner-centered, and are prominently located in the course.", bold: true, color: "0033A0" })] }),
      new Paragraph({ text: data.qmFeedback.qm2_3, spacing: { after: 200 } }),
      new Paragraph({ children: [new TextRun({ text: "QM 2.4: The relationship between learning objectives, learning activities, and assessments is made clear.", bold: true, color: "0033A0" })] }),
      new Paragraph({ text: data.qmFeedback.qm2_4, spacing: { after: 200 } }),
      new Paragraph({ children: [new TextRun({ text: "QM 2.5: The learning objectives are suited to and reflect the level of the course.", bold: true, color: "0033A0" })] }),
      new Paragraph({ text: data.qmFeedback.qm2_5, spacing: { after: 600 } })
    );

    // Alignment by CLOs
    docChildren.push(
      new Paragraph({
        children: [new TextRun({ text: "Alignment Organized By CLOs", bold: true, size: 32, color: "E36C09" })],
        alignment: AlignmentType.CENTER,
        spacing: { before: 400, after: 400 },
        pageBreakBefore: true,
      })
    );

    data.mappings.forEach((mapping, idx) => {
      docChildren.push(
        new Paragraph({
          children: [new TextRun({ text: `Course Learning Objective ${idx + 1}`, bold: true, size: 28, color: "0033A0" })],
          spacing: { before: 300, after: 100 },
        }),
        new Paragraph({ text: mapping.clo, spacing: { after: 200 } }),
        new Paragraph({ children: [new TextRun({ text: "Relevant Module Objectives & Associated Assessments/Activities", bold: true })] }),
      );

      mapping.alignedModules.forEach(mo => {
        docChildren.push(new Paragraph({ text: mo.objective, bullet: { level: 0 }, spacing: { after: 50 } }));
        mo.items.forEach(item => {
          docChildren.push(new Paragraph({ text: `[${item.type}] ${item.title}`, bullet: { level: 1 }, spacing: { after: 50 } }));
        });
      });

      docChildren.push(
        new Paragraph({ children: [new TextRun({ text: "Findings", bold: true })], spacing: { before: 200 } }),
        new Paragraph({ text: mapping.findings }),
        new Paragraph({ children: [new TextRun({ text: "Recommendations", bold: true })], spacing: { before: 100 } }),
        new Paragraph({ text: mapping.recommendations, spacing: { after: 400 } })
      );
    });

    // Alignment by Modules
    docChildren.push(
      new Paragraph({
        children: [new TextRun({ text: "Alignment Organized By Modules", bold: true, size: 32, color: "E36C09" })],
        alignment: AlignmentType.CENTER,
        spacing: { before: 400, after: 400 },
        pageBreakBefore: true,
      })
    );

    Array.from(modulesMap.values()).forEach((mod, idx) => {
      docChildren.push(
        new Paragraph({ children: [new TextRun({ text: `Module ${idx + 1}`, bold: true, size: 28, color: "0033A0" })], spacing: { before: 300 } }),
        new Paragraph({ children: [new TextRun({ text: "Relevant CLOs, MLO, & Associated Assessments/Activities", bold: true })] }),
        new Paragraph({ text: mod.objective, spacing: { after: 100 } }),
        new Paragraph({ children: [new TextRun({ text: "Associated CLOs:", bold: true })] }),
        ...mod.clos.map(c => new Paragraph({ text: c, bullet: { level: 0 } })),
        new Paragraph({ children: [new TextRun({ text: "Associated Items:", bold: true })] }),
        ...mod.items.map(i => new Paragraph({ text: `[${i.type}] ${i.title}`, bullet: { level: 0 } })),
        new Paragraph({ children: [new TextRun({ text: "Findings", bold: true })], spacing: { before: 200 } }),
        new Paragraph({ text: mod.findings.join(" ") }),
        new Paragraph({ children: [new TextRun({ text: "Recommendations", bold: true })], spacing: { before: 100 } }),
        new Paragraph({ text: mod.recommendations.join(" "), spacing: { after: 400 } })
      );
    });

    const doc = new Document({ sections: [{ children: docChildren }] });
    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${data.courseTitle.replace(/[^a-z0-9]/gi, '_')}_QM_Alignment_Report.docx`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-10 rounded-xl shadow-sm border border-slate-200 gap-6">
        <div>
          <h2 className="text-4xl font-extrabold text-slate-900">{data.courseTitle}</h2>
          <div className="flex items-center gap-3 mt-2">
            <p className="text-slate-500 text-xl">Course Design Alignment Map</p>
            <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
            <p className="text-slate-500 text-xl">{data.courseLength}</p>
          </div>
        </div>
        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <button onClick={downloadWord} className="px-8 py-4 text-lg font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-xl transition-all shadow-lg flex items-center justify-center gap-3">
            Download .docx
          </button>
          <button onClick={onReset} className="px-8 py-4 text-lg font-bold text-red-600 hover:text-white hover:bg-red-600 bg-white rounded-xl transition-all border border-red-200">
            Clear Report
          </button>
          <button onClick={onReset} className="px-8 py-4 text-lg font-bold text-slate-600 hover:text-slate-900 bg-slate-50 hover:bg-slate-100 rounded-xl transition-colors border border-slate-200">
            Reset
          </button>
        </div>
      </div>

      <div className="bg-blue-50 border-l-4 border-blue-500 p-10 rounded-r-xl">
        <h3 className="text-lg font-bold text-blue-800 uppercase mb-4">Executive Summary</h3>
        <p className="text-slate-700 text-2xl leading-relaxed">{data.overallSummary}</p>
      </div>

      <section className="bg-white rounded-2xl p-10 shadow-sm border border-slate-200">
        <h3 className="text-2xl font-bold text-[#0033A0] mb-8 border-b pb-4">Feedback On Objectives (QM Standard 2)</h3>
        <div className="space-y-6">
          {[
            { id: '2.1', title: 'Measurable Course Objectives', text: data.qmFeedback.qm2_1 },
            { id: '2.2', title: 'Consistent Module Objectives', text: data.qmFeedback.qm2_2 },
            { id: '2.3', title: 'Clearly Stated & Learner-Centered', text: data.qmFeedback.qm2_3 },
            { id: '2.4', title: 'Clear Alignment Line', text: data.qmFeedback.qm2_4 },
            { id: '2.5', title: 'Level Appropriateness', text: data.qmFeedback.qm2_5 }
          ].map((qm, i) => (
            <div key={i} className="bg-slate-50 p-6 rounded-xl border border-slate-100">
              <span className="text-xs font-black text-blue-500 uppercase tracking-widest block mb-1">QM {qm.id}</span>
              <h4 className="font-bold text-slate-800 text-lg mb-2">{qm.title}</h4>
              <p className="text-slate-600 leading-relaxed italic">"{qm.text}"</p>
            </div>
          ))}
        </div>
      </section>

      <div className="space-y-16">
        <h3 className="text-3xl font-bold text-center text-slate-800">Alignment Organized By CLOs</h3>
        {data.mappings.map((mapping, idx) => (
          <section key={idx} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="bg-slate-800 p-8 text-white">
              <span className="text-xs font-bold uppercase text-slate-400 tracking-widest block mb-2">CLO {idx + 1}</span>
              <h3 className="text-2xl font-semibold leading-snug">{mapping.clo}</h3>
            </div>
            <div className="p-8 space-y-8">
              {mapping.alignedModules.map((mo, moIdx) => (
                <div key={moIdx} className="border-l-4 border-blue-500 pl-6 py-2">
                  <p className="text-xl font-medium text-slate-800 mb-4">{mo.objective}</p>
